-- ─────────────────────────────────────────────────────────────
-- ARC : IBRAHIM ﷺ
-- ─────────────────────────────────────────────────────────────
insert into stories (id, title, title_ar, arc_type, total_chapters, status, order_index)
values ('arc_ibrahim', 'Ibrahim et le Feu', 'إِبْرَاهِيمُ وَالنَّارُ', 'prophets', 8, 'published', 2)
on conflict (id) do nothing;

insert into story_chapters (story_id, chapter_number, title, narrative, vocabulary, questions, values_shown, rewards)
values (
  'arc_ibrahim', 1, 'La rupture avec les idoles',
  E'Je suis un tapis ancien, tissé dans les ateliers de Babylone. Depuis des générations, on me dépose aux pieds des statues que les hommes vénèrent — des idoles de pierre, de bois, d''argile. Les gens leur apportent offrandes et prières, comme si ces objets immobiles pouvaient entendre ou répondre.\n\nCe jour-là, un jeune homme entre dans le temple. Il s''appelle Ibrahim. Son regard balaie les statues d''un bout à l''autre de la salle avec une expression que je ne peux pas mal interpréter : il ne voit pas des dieux — il voit des pierres.\n\nLe Coran nous rapporte qu''Ibrahim avait déjà, dans sa jeunesse, interrogé les étoiles, la lune et le soleil — cherchant son Seigneur. Et à chacun, quand il disparaissait à l''horizon, il concluait : ce qui disparaît ne peut être mon Seigneur. (Sourate Al-An''am, 6:76-78)\n\nCe questionnement n''était pas la révolte d''un adolescent. C''était la quête sincère d''une âme vers la vérité. Et cette vérité, Allah lui accorda de la voir clairement : il n''est de dieu qu''Allah seul — le Tawhid.\n\nIbrahim ne cherchait pas à provoquer. Il cherchait à comprendre pourquoi son peuple adorait ce que ses propres mains avaient façonné. Le Coran lui prête une parole de défi à son père : "Prends-tu des idoles pour divinités ? Je te vois, toi et ton peuple, dans un égarement manifeste." (Sourate Al-An''am, 6:74)\n\nLa leçon du tapis : la vérité ne se hérite pas mécaniquement. Ibrahim a reçu en héritage les idoles de son peuple, mais il a osé poser la question que personne ne posait. C''est cette question sincère qui l''a mené au Tawhid — et à Allah.',
  '[{"word_ar": "تَوْحِيد", "translit": "tawhid", "definition_fr": "monothéisme, unicité d''Allah", "example": "التَّوْحِيدُ أَسَاسُ الإِسْلَامِ (le tawhid est la base de l''islam)"}]',
  '[{"id":"ib1_q1","type":"comprehension","text":"Comment Ibrahim cherchait-il son Seigneur avant de recevoir la révélation, selon le Coran (6:76-78) ?","options":[{"text":"Il priait dans le temple des idoles","correct":false},{"text":"Il observait les astres et concluait que ce qui disparaît ne peut être Dieu","correct":true},{"text":"Il consultait les prêtres babyloniens","correct":false},{"text":"Il suivait les enseignements de son père","correct":false}]},{"id":"ib1_q2","type":"vocabulary","text":"Quel mot arabe désigne l''unicité d''Allah, concept central de la foi d''Ibrahim ?","options":[{"text":"صَبْر (sabr)","correct":false},{"text":"تَوْحِيد (tawhid)","correct":true},{"text":"رُؤْيَا (ru''ya)","correct":false},{"text":"حِكْمَة (hikma)","correct":false}]},{"id":"ib1_q3","type":"reflection","text":"Ibrahim ose questionner la religion de son peuple et de sa famille. Qu''est-ce qui demande le plus de courage selon toi : suivre la tradition ou chercher la vérité soi-même ?","reflection_prompt":"Prends le temps d''y réfléchir. Le tapis t''écoute."},{"id":"ib1_q4","type":"spaced_repetition","text":"Retiens ce mot pour la suite : تَوْحِيد (tawhid) = l''unicité d''Allah.","options":[],"spaced_ref":"ib1_q2"}]',
  ARRAY['tawhid','courage','questionnement'],
  '{"xp": 50, "coins": 15}'
);

insert into story_chapters (story_id, chapter_number, title, narrative, vocabulary, questions, values_shown, rewards)
values (
  'arc_ibrahim', 2, 'Le feu qui ne brûle pas',
  E'Je suis le même tapis, mais transporté par le vent de l''histoire jusqu''au cœur du bûcher. Le roi Nimrod a rendu son verdict : Ibrahim, qui a brisé les idoles du temple et accusé la grande statue de l''avoir fait, sera jeté vivant dans les flammes.\n\nLe Coran nous rapporte que le peuple rassembla du bois pendant des jours pour construire le plus grand feu que Babylone ait jamais vu. Les prêtres bénissaient le bûcher. La foule regardait.\n\nEt Ibrahim fut lancé dans les flammes.\n\nCe que le Coran dit ensuite est l''un des versets les plus saisissants de tout le Livre : "Nous dîmes : Ô feu, sois froid et sans danger pour Ibrahim !" (Sourate Al-Anbiya, 21:69)\n\nFroid. Et sans danger.\n\nNon pas que le feu disparaisse — il continuait de brûler. Mais Allah, qui a créé le feu et lui a donné la propriété de brûler, peut lui ordonner de ne pas brûler. Ibrahim sortit des flammes indemne, sous les yeux de ceux qui l''avaient condamné.\n\nLe Coran ajoute que cette épreuve fut une défaite pour ceux qui avaient comploté contre Ibrahim. (Sourate Al-Anbiya, 21:70)\n\nJe reste sur le sol, intact. Le feu ne touche pas ce que Allah protège.\n\nLa leçon du tapis : la confiance absolue en Allah — le tawakkul — ne demande pas l''absence de danger. Ibrahim était bel et bien dans les flammes. Sa foi n''a pas annulé le danger : elle a permis à Allah d''agir. C''est cela, le tawakkul.',
  '[{"word_ar": "خَلِيل", "translit": "khalil", "definition_fr": "ami intime, bien-aimé — titre accordé à Ibrahim par Allah", "example": "وَاتَّخَذَ اللَّهُ إِبْرَاهِيمَ خَلِيلًا (Allah a pris Ibrahim pour ami intime) — Sourate An-Nisa, 4:125"}]',
  '[{"id":"ib2_q1","type":"comprehension","text":"Quel ordre Allah donna-t-il au feu quand Ibrahim y fut jeté, selon le Coran (21:69) ?","options":[{"text":"De s''éteindre immédiatement","correct":false},{"text":"D''être froid et sans danger pour Ibrahim","correct":true},{"text":"De ne pas toucher ses vêtements","correct":false},{"text":"De lui montrer une vision","correct":false}]},{"id":"ib2_q2","type":"vocabulary","text":"Quel titre le Coran accorde-t-il à Ibrahim, signifiant ''ami intime d''Allah'' ?","options":[{"text":"رَسُول (rasul)","correct":false},{"text":"نَبِيّ (nabi)","correct":false},{"text":"خَلِيل (khalil)","correct":true},{"text":"إِمَام (imam)","correct":false}]},{"id":"ib2_q3","type":"reflection","text":"Ibrahim entre dans le feu avec une confiance totale en Allah. As-tu déjà vécu une situation difficile où tu as dû faire confiance sans voir le résultat ?","reflection_prompt":"Il n''y a pas de mauvaise réponse."},{"id":"ib2_q4","type":"spaced_repetition","text":"Rappel : تَوْحِيد (tawhid) du chapitre 1. Nouveau mot : خَلِيل (khalil) = ami intime d''Allah.","options":[],"spaced_ref":"ib2_q2"}]',
  ARRAY['tawakkul','protection_divine','epreuve'],
  '{"xp": 60, "coins": 18}'
);

-- ─────────────────────────────────────────────────────────────
-- ARC : MOUSSA ﷺ
-- ─────────────────────────────────────────────────────────────
insert into stories (id, title, title_ar, arc_type, total_chapters, status, order_index)
values ('arc_moussa', 'Moussa et Pharaon', 'مُوسَى وَفِرْعَوْنُ', 'prophets', 10, 'published', 3)
on conflict (id) do nothing;

insert into story_chapters (story_id, chapter_number, title, narrative, vocabulary, questions, values_shown, rewards)
values (
  'arc_moussa', 1, 'L''enfant du fleuve',
  E'Je suis un jonc tressé, transformé en berceau. Un berceau que des mains tremblantes ont confié aux eaux du Nil, dans la nuit profonde de l''Égypte ancienne.\n\nPharaon avait décrété la mort de tous les nouveau-nés mâles des Enfants d''Israël. La peur s''était installée dans chaque foyer. Mais Allah allait montrer que Ses plans surpassent ceux des tyrans.\n\nLe Coran nous rapporte qu''Allah inspira à la mère de Moussa : "Allaite-le ; puis, lorsque tu craindras pour lui, mets-le dans le fleuve. Ne crains pas et ne t''attriste pas : Nous te le rendrons et ferons de lui l''un des envoyés." (Sourate Al-Qasas, 28:7)\n\nCette inspiration — ce wahy — n''était pas une prophétie ordinaire. C''était une promesse divine enveloppée dans une instruction. La mère de Moussa devait accomplir un acte qui semblait absurde : confier son enfant au fleuve pour le sauver. Mais Allah lui avait donné la certitude que ce fleuve ramènerait son fils.\n\nLe berceau flotta. La rivière porta l''enfant jusqu''aux rives du palais de Pharaon — le palais même de celui qui ordonnait la mort des enfants israélites. Asiya, l''épouse de Pharaon, l''aperçut et ressentit pour lui un amour immédiat. Le Coran dit qu''elle dit à Pharaon : "Il sera une consolation pour moi et pour toi. Ne le tuez pas !" (Sourate Al-Qasas, 28:9)\n\nLa leçon du tapis : l''ennemi d''un peuple a élevé, nourri et protégé celui qui serait sa propre perte. Allah utilise les moyens que nous ne pouvons pas imaginer.',
  '[{"word_ar": "وَحْي", "translit": "wahy", "definition_fr": "révélation ou inspiration divine", "example": "وَأَوْحَيْنَا إِلَى أُمِّ مُوسَى (Nous avons inspiré la mère de Moussa) — Sourate Al-Qasas, 28:7"}]',
  '[{"id":"ms1_q1","type":"comprehension","text":"Quelle promesse Allah fit-Il à la mère de Moussa quand elle le confia au Nil (28:7) ?","options":[{"text":"Que le fleuve le porterait vers une terre étrangère","correct":false},{"text":"Qu''il le lui rendrait et en ferait un envoyé","correct":true},{"text":"Que Pharaon mourrait avant de le voir","correct":false},{"text":"Qu''il serait protégé par les anges","correct":false}]},{"id":"ms1_q2","type":"vocabulary","text":"Quel mot arabe désigne la révélation ou l''inspiration divine reçue par la mère de Moussa ?","options":[{"text":"رُؤْيَا (ru''ya)","correct":false},{"text":"وَحْي (wahy)","correct":true},{"text":"دُعَاء (du''a)","correct":false},{"text":"صَلَاة (salat)","correct":false}]},{"id":"ms1_q3","type":"reflection","text":"La mère de Moussa accomplit un acte qui semblait contre toute logique pour obéir à Allah. Y a-t-il des moments où la foi demande d''agir contre notre propre peur ?","reflection_prompt":"Partage ta réflexion."},{"id":"ms1_q4","type":"spaced_repetition","text":"Retiens : وَحْي (wahy) = inspiration ou révélation divine.","options":[],"spaced_ref":"ms1_q2"}]',
  ARRAY['confiance','providence','courage_maternel'],
  '{"xp": 50, "coins": 15}'
);

insert into story_chapters (story_id, chapter_number, title, narrative, vocabulary, questions, values_shown, rewards)
values (
  'arc_moussa', 2, 'La voix du buisson ardent',
  E'Je suis tissé de fils blancs et bruns, posé sur un rocher au flanc du mont Sinaï. Le désert est silencieux. Un homme marche, conduisant ses troupeaux. C''est Moussa — des années ont passé depuis le Nil. Il vit maintenant à Madyan, loin de l''Égypte et de ses souvenirs.\n\nSoudain, il aperçoit une flamme dans un buisson. Une flamme qui brûle sans consumer le bois. Il s''en approche, intrigué.\n\nLe Coran nous rapporte que lorsqu''il fut près de la vallée sainte de Tuwa, une voix l''appela : "Ô Moussa, Je suis ton Seigneur. Ôte tes sandales, car tu es dans la vallée sacrée de Tuwa." (Sourate Ta-Ha, 20:11-12)\n\nPuis la révélation continue : Allah Se présente, ordonne à Moussa d''accomplir la prière et de Le rappeler. Il lui montre que son bâton peut devenir un serpent, que sa main peut briller d''une lumière blanche — deux signes pour la mission à venir. (Sourate Ta-Ha, 20:14-22)\n\nEt enfin la mission : "Va vers Pharaon — il a outrepassé toutes les limites." (Sourate Ta-Ha, 20:24)\n\nMoussa, un berger en exil, se retrouve investi d''une mission qui dépasse tout ce qu''il aurait pu imaginer. Le buisson ne brûlait pas seulement le bois — il brûlait la vie ordinaire de Moussa pour en faire quelque chose d''extraordinaire.\n\nLa leçon du tapis : Allah choisit Ses envoyés non parce qu''ils sont parfaits, mais parce qu''ils Lui font confiance. Moussa n''avait ni armée ni palais — juste un bâton et une foi naissante.',
  '[{"word_ar": "رِسَالَة", "translit": "risala", "definition_fr": "message, mission prophétique", "example": "بَلَّغَ الرِّسَالَةَ (il a transmis le message) — concept central en Sourate Al-Ma''ida"}]',
  '[{"id":"ms2_q1","type":"comprehension","text":"Que dit Allah à Moussa quand il approche du buisson ardent (20:11-12) ?","options":[{"text":"Il lui annonce qu''il sera roi d''Égypte","correct":false},{"text":"Il lui dit d''ôter ses sandales car il est en terre sacrée, et Se révèle comme son Seigneur","correct":true},{"text":"Il lui demande d''aller chercher de l''eau","correct":false},{"text":"Il lui annonce la mort de Pharaon","correct":false}]},{"id":"ms2_q2","type":"vocabulary","text":"Quel mot arabe désigne le message ou la mission confiée à un prophète ?","options":[{"text":"وَحْي (wahy)","correct":false},{"text":"رِسَالَة (risala)","correct":true},{"text":"حِكْمَة (hikma)","correct":false},{"text":"تَوْحِيد (tawhid)","correct":false}]},{"id":"ms2_q3","type":"reflection","text":"Moussa était berger en exil quand Allah lui confia une mission immense. Penses-tu que nos ''petits'' moments prépèrent parfois de grandes responsabilités ?","reflection_prompt":"Réfléchis librement."},{"id":"ms2_q4","type":"spaced_repetition","text":"Rappel : وَحْي (wahy) du chapitre 1. Nouveau mot : رِسَالَة (risala) = mission prophétique.","options":[],"spaced_ref":"ms2_q2"}]',
  ARRAY['vocation','mission','humilite'],
  '{"xp": 60, "coins": 18}'
);

