-- ARC : MARYAM (AS)
-- ─────────────────────────────────────────────────────────────
insert into stories (id, title, title_ar, arc_type, total_chapters, status, order_index)
values ('arc_maryam', 'Maryam, la choisie', 'مَرْيَمُ الصِّدِّيقَةُ', 'prophets', 6, 'published', 4)
on conflict (id) do nothing;

insert into story_chapters (story_id, chapter_number, title, narrative, vocabulary, questions, values_shown, rewards)
values (
  'arc_maryam', 1, 'La consacrée du temple',
  E'Je suis un tapis de prière usé par des millénaires de prosternations, posé sur le sol froid du temple de Jérusalem — Bayt Al-Maqdis. Les pierres ici portent la mémoire de mille prières.\n\nUne femme arrive, enceinte et en fin de grossesse. Elle avait fait un voeu : si Allah lui accordait un enfant, elle Le consacrerait entièrement à Son service au temple. Elle ignorait encore que cet enfant serait une fille — Maryam.\n\nLe Coran rapporte sa prière : "Seigneur, je Te consacre ce qu''il y a dans mon ventre, libéré de tout attachement mondain. Accepte-le de moi, car Tu es l''Audient, l''Omniscient." (Sourate Al-Imran, 3:35)\n\nMaryam grandit dans le temple. Allah lui accorda une faveur extraordinaire : chaque fois que Zakariya — le prophète qui la gardait — entrait dans son mihrab, il trouvait auprès d''elle une nourriture qu''il n''avait pas apportée. Il lui demanda d''où cela venait. Le Coran rapporte qu''elle répondit que cela venait d''Allah — car Allah pourvoit à qui Il veut sans compter. (Sourate Al-Imran, 3:37)\n\nMaryam ne cherchait pas les honneurs. Elle cherchait Allah. Et Allah l''honora d''une façon qui dépassait toute attente humaine.\n\nLe Coran dit qu''Allah choisit Maryam et la purifia et la choisit parmi toutes les femmes du monde. (Sourate Al-Imran, 3:42)\n\nLa leçon du tapis : la dévotion sincère et discrète ne passe pas inaperçue auprès d''Allah. Maryam ne priait pas pour être remarquée — elle priait parce qu''elle aimait Allah.',
  '[{"word_ar": "قُنُوت", "translit": "qunut", "definition_fr": "dévotion obéissante, prosternation humble et sincère", "example": "كَانَتْ مِنَ الْقَانِتِينَ (elle était parmi les dévots) — Sourate Al-Imran, 3:43"}]',
  '[{"id":"mr1_q1","type":"comprehension","text":"Quelle faveur particulière Allah accordait-Il à Maryam dans son mihrab, étonnant Zakariya ?","options":[{"text":"Elle récitait le Coran sans l''avoir appris","correct":false},{"text":"Une nourriture qu''il n''avait pas apportée se trouvait auprès d''elle","correct":true},{"text":"Elle ne dormait jamais","correct":false},{"text":"Des anges priaient avec elle","correct":false}]},{"id":"mr1_q2","type":"vocabulary","text":"Quel mot arabe désigne la dévotion obéissante et la prosternation humble ?","options":[{"text":"تَوْحِيد (tawhid)","correct":false},{"text":"قُنُوت (qunut)","correct":true},{"text":"صَبْر (sabr)","correct":false},{"text":"وَحْي (wahy)","correct":false}]},{"id":"mr1_q3","type":"reflection","text":"Maryam était dévouée en secret, sans chercher à être vue. Penses-tu que nos actes d''adoration privés ont autant de valeur que ceux accomplis en groupe ?","reflection_prompt":"Il n''y a pas de mauvaise réponse."},{"id":"mr1_q4","type":"spaced_repetition","text":"Retiens : قُنُوت (qunut) = dévotion humble et sincère.","options":[],"spaced_ref":"mr1_q2"}]',
  ARRAY['devotion','sincerite','election_divine'],
  '{"xp": 50, "coins": 15}'
);

